<template>
  <div class="main">
    <div class="content">
    

      <Nav index = '1'></Nav>
      <div class="show_wrap">
              <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              北京计量科学院
              </h1>
        <div class="row height55">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">设备地址</h4>
              <div class="card_show">
                <div class="img_map" id ='allmap'>
            
                </div>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
               <h4 class="card_title">设备信息</h4>
              <div class="card_show"> 
                <div class="model_table">
                  <div class="col" v-for='(value , key , index) in data'>
                    <div class="row">{{key}}</div>
                    <div class="row">{{value}}</div>
                  </div>
                </div>
              </div>
            </div>
        </div>
        </div>
        <div class="row height45">
            <div class="col">
              <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
               <h4 class="card_title">实时数据</h4>
              <div class="chartpost" ref = 'mychart'>

              </div>
            </div>
        </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'


export default {
  name: 'Index',
  components:{Nav},
  data () {
    return {
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      timer:null,
      marker:[],
      data:{
            "医院名称": "",
            "型号规格": "",
            "类型": "",
            "出厂编号": "",
            "生产厂家": "",
            "医院级别": "",
            "等级": "",
            "医院所在区县": "",
            "检定人员": "",
            "数据检定日期": "",
            "证书编号": "",
            "测量条件kv": "",
            "测量条件mA": "",
            "测量条件s": "",
            "测量条件mAs(移动专用）": "",
            "重复性": "",
            "重复性计算结果": "",
            "半值层 铝板厚度mmAL": "",
            "加片后半值层数据": "",
            "线性20mAs？": "",
            "线性数据20mAs": "",
            "线性数据10mAs": "",
            "线性计算结果": ""
        }
    }
  },
  mounted() {
      this.initMap();
      this.ininChart();
      this.initTable()
      this.timer = setInterval(()=>{
          this.pushData()
      }, 1000)
  },
  methods: {
      initMap(){
            var map = new BMap.Map("allmap");
            var map = new BMap.Map("allmap");
            var point = new BMap.Point(116.404, 39.915);
            map.enableScrollWheelZoom();                            //启用滚轮放大缩小
            map.centerAndZoom(point, 11); 
            map.setMapStyle({style:'midnight'});


            var pointList = [
                {
                    j:116.42,
                    w:39.93
                },
                {
                    j:116.37,
                    w:39.92
                },
                {
                    j:116.22,
                    w:39.9
                },
                {
                    j:116.1,
                    w:39.93
                },{
                    j:116.60,
                    w:39.92
                },{
                    j:116.10,
                    w:39.93
                },{
                    j:116.65,
                    w:39.92
                },{
                    j:116.23,
                    w:40.22
                }
            ]
            for(let i = 0 ; i < pointList.length ; i ++){
                var pt = new BMap.Point(pointList[i].j, pointList[i].w);
                var myIcon = new BMap.Icon("https://s2.ax1x.com/2019/05/14/EohY7t.png", new BMap.Size(50,50));
                this.marker.push(new BMap.Marker(pt,{icon:myIcon}));    // 创建标注
                map.addOverlay(this.marker[i]);                             // 将标注添加到地图中
                this.marker[i].addEventListener('click' , ()=>{
                    this.data = this.gloData[i];
                    this.ininChart();
                })
            }
      },
      initTable(){
        var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
        this.data = this.gloData[index];
      },
      ininChart(){
        

        // 基于准备好的dom，初始化echarts实例
        this.chart = echarts.init(this.$refs.mychart);
        var timeArr = [];
        for (var index = 0; index < 30; index++) {
            timeArr.push(index)
        }

        var dataArr = [];

        for (var i = 0; i < 30; i++) {
            dataArr.push(Math.random() * 300);
        }

        // 指定图表的配置项和数据
        var option = {
            title: {
                text: "单位：",
                textStyle: {
                    color: "#597d97",
                    fontWeight: 100
                },
                left: 20
            },
            color: ['#3398DB'],
            tooltip: {
                trigger: 'axis',
                axisPointer: { // 坐标轴指示器，坐标轴触发有效
                    type: 'shadow' // 默认为直线，可选为：'line' | 'shadow'
                }
            },
            grid: {
                left: '3%',
                right: '4%',
                bottom: '3%',
                containLabel: true,
                axisLabel: {
                    textStyle: {
                        color: "#597d97"
                    }
                }
            },
            xAxis: [{
                type: 'category',
                data: timeArr,
                axisTick: {
                    alignWithLabel: true
                },
                axisLabel: {
                    textStyle: {
                        color: "#667e9a"
                    }
                },
                axisLine: {
                    lineStyle: {
                        color: "#063d7e"
                    }
                }
            }],
            yAxis: [{
                type: 'value',
                axisLabel: {
                    textStyle: {
                        color: "#667e9a"
                    }
                },
                axisLine: {
                    lineStyle: {
                        color: "#063d7e"
                    }
                }
            }],
            series: [{
                name: '辐射量',
                type: 'bar',
                barWidth: '60%',
                data: dataArr,
                itemStyle: {
                    normal: {
                        color: "#20d090"
                    }
                }
            }],
            legend: {
                data: ['辐射量'],
                textStyle: {
                    color: "#fff"
                }
            }
        };

        // 使用刚指定的配置项和数据显示图表。
        this.chart.setOption(option);
      },
      pushData(){
        var option = this.chart.getOption();
        var dataArr = option.series[0].data;
        dataArr.shift()
        dataArr.push(Math.random() * 300);
        var timeArr = option.xAxis[0].data;
        timeArr.shift()
        timeArr.push( timeArr[timeArr.length-1] + 1);
        option.series[0].data = dataArr
        option.xAxis[0].data = timeArr
        this.chart.setOption(option);
      }
  },
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
</style>



