<template>
  <div class="main">
    <div class="content">
    
        <Nav index = '2'/>
      <div class="show_wrap">
                    <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              北京计量科学院
              </h1>
        <div class="row height100">
            <div class="col width60 height100">
                <div class="col_inner height60">
                    <div class="card active">
                    <b></b>
                    <b></b>
                    <b></b>
                    <b></b>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <h4 class="card_title">设备分布</h4>
                    <div class="card_show">
                        <div class="img_map" id ='allmap' style='height:500px'>
            
                        </div>
                    </div>  
                    </div>
                </div>
                 <div class="col_inner height40 padding_top30">
                    <div class="card active ">
                    <b></b>
                    <b></b>
                    <b></b>
                    <b></b>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <div class="line a"></div>
                    <h4 class="card_title">重复性</h4>
                    <div class="card_show">
                        <div class="linechart width50 height100  fl" ref= 'mycharta'></div>
                        <div class="linechart width50 height100  fl" ref= 'mychartb'></div>
                    </div>
                    </div>
                </div>
            </div>
            <div class="col width40 height100">
                <div class="card active">
                <b></b>
                <b></b>
                <b></b>
                <b></b>
                <div class="line a"></div>
                <div class="line a"></div>
                <div class="line a"></div>
                <div class="line a"></div>
                <h4 class="card_title">线性</h4>
                <div class="card_show">
                    <div class="linechart height50" ref= 'mychartc'></div>
                    <div class="linechart height50" ref= 'mychartd'></div>
                </div>
                </div>
                </div>
          </div>
        </div>

        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'

export default {
  name: 'Interaction',
  components:{Nav},
  data () {
    return {
        marker:[],
        msg: 'Welcome to Your Vue.js App',
        chart:null,
        tableData:[
            ['北京航星医院', 'DR 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城'],
            ['北京航星医院', 'AX 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城']
        ],
        data:{
            "医院名称": "",
            "型号规格": "",
            "类型": "",
            "出厂编号": "",
            "生产厂家": "",
            "医院级别": "",
            "等级": "",
            "医院所在区县": "",
            "检定人员": "",
            "数据检定日期": "",
            "证书编号": "",
            "测量条件kv": "",
            "测量条件mA": "",
            "测量条件s": "",
            "测量条件mAs(移动专用）": "",
            "重复性": "",
            "重复性计算结果": "",
            "半值层 铝板厚度mmAL": "",
            "加片后半值层数据": "",
            "线性20mAs？": "",
            "线性数据20mAs": "",
            "线性数据10mAs": "",
            "线性计算结果": ""
        },
    }
  },
  mounted() {
      this.initMap()
      this.initLine()
  },
  methods: {
      initLine(){

            let getArr = ()=>{
                var arr = []
                for(var index = 0 ; index < 5 ; index++){
                    arr.push(Math.random() * 1500)
                }
                return arr
            }
            var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
            this.data = this.gloData[index];
        // 基于准备好的dom，初始化echarts实例
            // 基于准备好的dom，初始化echarts实例
            var myCharta = echarts.init(this.$refs.mycharta);

            var myChartb = echarts.init(this.$refs.mychartb);


            var myChartc = echarts.init(this.$refs.mychartc);
            var myChartd = echarts.init(this.$refs.mychartd);
            var option = {
                xAxis: {
                    type: 'category',
                    data: ['01', '02', '03', '04', '05'],
                    axisLabel: {
                        textStyle: {
                            color: "#83ecf3"
                        }
                    },
                    axisLine: {
                        lineStyle: {
                            color: "#063d7e"
                        }
                    }
                },
                yAxis: {
                    type: 'value',
                    axisLabel: {
                        textStyle: {
                            color: "#fff"
                        }
                    },
                    axisLine: {
                        lineStyle: {
                            color: "#fff"
                        }
                    }
                },
                series: [{
                    data: [1500*Math.random(), 1500*Math.random(), 1500*Math.random(), 1500*Math.random(), 1500*Math.random()],
                    type: 'line',
                    itemStyle: {
                        normal: {
                            lineStyle: {
                                color: '#87d75c'
                            }
                        }
                    },
                }]
            };


            // 使用刚指定的配置项和数据显示图表。
            myCharta.setOption(option);
            console.log(option.series[0].data);
            option.series[0].data = getArr()
            myChartb.setOption(option);
            option.series[0].data= getArr() 
            myChartc.setOption(option);
            option.series[0].data =  getArr()
            myChartd.setOption(option);
      },
      initMap(){
            var map = new BMap.Map("allmap");
            var map = new BMap.Map("allmap");
            var point = new BMap.Point(116.404, 39.915);
            map.enableScrollWheelZoom();                            //启用滚轮放大缩小
            map.centerAndZoom(point, 11); 
            map.setMapStyle({style:'midnight'});
            var pointList = [
                {
                    j:116.42,
                    w:39.93
                },
                {
                    j:116.37,
                    w:39.92
                },
                {
                    j:116.22,
                    w:39.9
                },
                {
                    j:116.1,
                    w:39.93
                },{
                    j:116.60,
                    w:39.92
                },{
                    j:116.10,
                    w:39.93
                },{
                    j:116.65,
                    w:39.92
                },{
                    j:116.23,
                    w:40.22
                }
            ]
            for(let i = 0 ; i < pointList.length ; i ++){
                var pt = new BMap.Point(pointList[i].j, pointList[i].w);
                var myIcon = new BMap.Icon("https://s2.ax1x.com/2019/05/14/EohY7t.png", new BMap.Size(30,30));
                this.marker.push(new BMap.Marker(pt,{icon:myIcon}));    // 创建标注
                map.addOverlay(this.marker[i]);                             // 将标注添加到地图中
                this.marker[i].addEventListener('click' , ()=>{
                    this.data = this.gloData[i];
                    this.initLine();
                })
            }
      },
  },
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
.card_show img{
    display:block;
    width:80%;
    margin:0 auto;
}
</style>



