<template>
  <div class="main">

  <el-dialog
        title="提示"
        :visible.sync="dialogVisible"
        width="30%"
        append-to-body
        >
        <div>
            <div class="card_show"> 
                <div class="model_table">
                  <div class="col" v-for='(value , key , index) in data'>
                    <div class="row">{{key}}</div>
                    <div class="row">{{value}}</div>
                  </div>
                </div>
              </div>
        </div>
        <span slot="footer" class="dialog-footer">
            <el-button @click="dialogVisible = false">取 消</el-button>
            <el-button type="primary" @click="dialogVisible = false">确 定</el-button>
        </span>
    </el-dialog>
    <div class="content">
      <Nav index = '4'></Nav>
      <div class="show_wrap">
              <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              北京计量科学院
              </h1>
        <div class="row height100">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">设备分布</h4>
              <div class="card_show">
                <div class="img_map" ref = 'mychart' style='height:100%'>
                </div>
              </div>
            </div>
          </div>
        </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'

import beijing from '../../node_modules/echarts/map/json/province/beijing.json'

export default {
  name: 'Index',
  components:{Nav},
  data () {
    return {
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      timer:null,
      marker:[],
      dialogVisible:false,
      data:{
            "医院名称": "",
            "型号规格": "",
            "类型": "",
            "出厂编号": "",
            "生产厂家": "",
            "医院级别": "",
            "等级": "",
            "医院所在区县": "",
            "检定人员": "",
            "数据检定日期": "",
            "证书编号": "",
            "测量条件kv": "",
            "测量条件mA": "",
            "测量条件s": "",
            "测量条件mAs(移动专用）": "",
            "重复性": "",
            "重复性计算结果": "",
            "半值层 铝板厚度mmAL": "",
            "加片后半值层数据": "",
            "线性20mAs？": "",
            "线性数据20mAs": "",
            "线性数据10mAs": "",
            "线性计算结果": ""
        }
    }
  },
  mounted() {
      // this.initMap();
      this.initTable();
      this.initBjMap()
  },
  methods: {
        initMap(){
            var map = new BMap.Map("allmap");
            var map = new BMap.Map("allmap");
            var point = new BMap.Point(116.404, 39.915);

            map.enableScrollWheelZoom();                            //启用滚轮放大缩小
            map.centerAndZoom(point, 11); 
            map.setMapStyle({style:'midnight'});

            var pointList = [
                {
                    j:116.42,
                    w:39.93
                },
                {
                    j:116.37,
                    w:39.92
                },
                {
                    j:116.22,
                    w:39.9
                },
                {
                    j:116.1,
                    w:39.93
                }
            ]
            for(let i = 0 ; i < pointList.length ; i ++){
                var pt = new BMap.Point(pointList[i].j, pointList[i].w);
                var myIcon = new BMap.Icon("https://s2.ax1x.com/2019/05/14/EohY7t.png", new BMap.Size(70,70));
                this.marker.push(new BMap.Marker(pt,{icon:myIcon}));    // 创建标注
                map.addOverlay(this.marker[i]);                             // 将标注添加到地图中
                this.marker[i].addEventListener('click' , ()=>{
                    this.dialogVisible = true;
                })
            }
        },
        initTable(){
            var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
            this.data = this.gloData[index];
        },
        initBjMap(){
            echarts.registerMap('bj', beijing);
                var geoCoordMap = {
                    '海淀区':[116.309983,39.966935],
                    '廊坊区':[116.405419,39.912057],
                    '房山区':[116.136358,39.738279],
                    '昌平区':[116.205348,40.22656],
                    '顺义区':[116.674479,40.141895],
                    '香河县':[116.968836,39.772006],
                    '密云区':[116.817058,40.439516],

                }
                var data = [
                    {name:'海淀区', value: 79},
                    {name:'廊坊区', value: 53},
                    {name:'房山区', value: 137},
                    {name:'昌平区', value: 125},
                    {name:'顺义区', value: 70},
                    {name:'香河县', value: 48},
                    {name:'密云区', value: 63},

                
                ];
            var convertData = function (data) {
                var res = [];
                for (var i = 0; i < data.length; i++) {
                    var geoCoord = geoCoordMap[data[i].name];
                    if (geoCoord) {
                        res.push({
                            name: data[i].name,
                            value: geoCoord.concat(data[i].value)
                        });
                    }
                }
                return res;
            };

            var option = {
                    title: {
                        // text: '北京市市地图',
                        left: 'center',
                        top: '2%',
                        textStyle: {
                            color: '#fff'
                        }
                    },
                    backgroundColor: '',
                    tooltip: {
                        formatter : function(e){
                            if (typeof(e.value)[2] == "undefined") {
                                return e.name;
                            }else{
                                return '设备数量<br>'+e.name + ':' + e.value[2] + '';
                            }
                        }
                    },
                    geo: {
                        map: 'bj',
                        show: true,
                        roam: false,
                        label: {
                            emphasis: {
                                show: false
                            }
                        },
                        itemStyle: {
                            normal: {
                                areaColor: '#031525',
                                borderColor: '#1773c3',
                                shadowColor: '#031525',
                                shadowBlur: 20
                            }
                        },
                      zoom:1.2,
                    },
                    series: [{
                        type: 'map',
                        map: 'ls',
                        geoIndex: 1,
                        aspectScale: 0.75, //长宽比
                        zoom:1.2,
                        label: {
                            normal: {
                                formatter: '{b}',
                                show: true,
                                textStyle:{
                                    color:'#fff'
                                }
                            },
                            emphasis: {
                                show: false,
                                textStyle: {
                                    color: '#05C3F9'
                                }
                            }
                        },
                        roam: false,
                        itemStyle: {
                            normal: {
                                areaColor: 'transparent',
                                borderColor: '#3B5077',
                                borderWidth: 1
                            },
                            emphasis: {
                                areaColor: '#070d18',
                                shadowColor: '#1773c3',
                                shadowBlur: 20
                            }
                        },
                        data: data,
                    },
                    {
                        name: '设备数量',
                        type: 'scatter',
                        coordinateSystem: 'geo',
                        symbol: 'circle',
                        symbolSize: function (val) {
                            return val[2] / 1.4;
                        },
                        label: {
                            normal: {
                                show: true,
                                formatter: function(value){
                                    return value.value[2]
                                },
                                textStyle: {
                                    color: '#fff',
                                    fontSize: 12,
                                }
                            }
                        },
                        itemStyle: {
                            normal: {
                                color: '#33A875', //标志颜色
                            }
                        },
                        zlevel: 6,
                        data: convertData(data),
                    }
                    ]
            }

            var myChart = echarts.init(this.$refs.mychart);

            myChart.setOption(option);


      }
  },
}
</script>
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
</style>



